
"use client";

import React,{useMemo,useState} from "react";
import { Search,Store,Star,MapPin,CalendarDays,LayoutDashboard,CheckCircle2,Wallet,Users,ClipboardList,Wand2,Crown,UserPlus,CreditCard,Building2,Send,DollarSign,Database,ShieldCheck,TestTube2,Navigation,Brain,Mail,Smartphone,Map } from "lucide-react";

const businessName=process.env.NEXT_PUBLIC_BUSINESS_NAME||"LMH Enterprise LLC";
const categories=[
{key:"all",label:"All",zones:["Main area","Guest flow","Vendor zone","Safety area"],checklist:["Define event goal","Set budget","Add vendors","Confirm timeline"]},
{key:"wedding",label:"Wedding",zones:["Ceremony aisle","Reception seating","Dance floor","Photo area"],checklist:["Confirm flowers","Create seating chart","Book DJ","Plan weather backup"]},
{key:"family",label:"Family & BBQ",zones:["Grill zone","Food line","Games area","Kids area"],checklist:["Confirm grill fuel","Add coolers and ice","Add trash/recycling","Confirm shade"]},
{key:"corporate",label:"Corporate",zones:["Registration","Main room","Breakouts","Catering"],checklist:["Prepare badges","Confirm projector","Add agenda","Plan Wi-Fi"]},
{key:"music",label:"Music & Concert",zones:["Stage","Sound booth","Audience area","Vendor row"],checklist:["Confirm sound","Add lighting","Secure power","Plan crowd control"]},
{key:"political",label:"Political & Civic",zones:["Podium","Media zone","VIP","Security"],checklist:["Confirm permits","Review compliance","Set media access","Plan crowd flow"]}
];
const starterVendors=[
{name:"Elite Sound DJs",category:"Music & Concert",service:"DJ / Music",city:"Stafford, VA",price:"$350 - $900",rating:4.9,badge:"Featured",plan:"featured",revenue:49,lat:38.4221,lng:-77.4083},
{name:"Fresh Flame Catering",category:"Wedding",service:"Catering",city:"Fredericksburg, VA",price:"$15 - $45 / guest",rating:4.8,badge:"Elite",plan:"elite",revenue:149,lat:38.3032,lng:-77.4605},
{name:"Venue Luxe Hall",category:"Corporate",service:"Venue",city:"Stafford, VA",price:"$800 - $5,000",rating:4.9,badge:"Featured",plan:"featured",revenue:49,lat:38.4331,lng:-77.4100},
{name:"GlowPro Lighting",category:"Wedding",service:"Lighting / AV",city:"Washington, DC",price:"$300 - $1,500",rating:4.7,badge:"Starter",plan:"starter",revenue:0,lat:38.9072,lng:-77.0369},
{name:"CivicStage Productions",category:"Political & Civic",service:"Stage / Civic Events",city:"Northern VA",price:"$1,500 - $7,500",rating:4.6,badge:"Elite",plan:"elite",revenue:149,lat:38.8048,lng:-77.0469}
];
const plans=[
{key:"starter",name:"Starter",price:"$0/mo",amount:0,features:["Basic vendor card","Marketplace listing","Manual booking requests"]},
{key:"featured",name:"Featured",price:"$49/mo",amount:49,features:["Priority ranking","Featured badge","More lead visibility"]},
{key:"elite",name:"Elite",price:"$149/mo",amount:149,features:["Top placement","Elite badge","Homepage spotlight","Priority leads"]},
{key:"ai",name:"AI Premium Planner",price:"$19/mo",amount:19,features:["Premium AI event plan","Vendor matching","Budget assistant","Timeline generator"]}
];
function money(v){return new Intl.NumberFormat("en-US",{style:"currency",currency:"USD"}).format(Number(v||0))}
async function postJson(path,body={}){const res=await fetch(path,{method:"POST",headers:{"Content-Type":"application/json"},body:JSON.stringify(body)});return res.json()}
async function getJson(path){const res=await fetch(path);return res.json()}

export default function Page(){
const[tab,setTab]=useState("live"),[query,setQuery]=useState(""),[activeKey,setActiveKey]=useState("all");
const[eventName,setEventName]=useState("GatherGenius Event"),[eventLocation,setEventLocation]=useState("Stafford, VA"),[eventBudget,setEventBudget]=useState(5200);
const[vendors,setVendors]=useState(starterVendors),[bookings,setBookings]=useState([{id:"BK-1001",customer:"James Sims",vendor:"Elite Sound DJs",amount:850,commission:85,status:"Requested"}]);
const[vendorForm,setVendorForm]=useState({name:"",service:"",city:"",price:"",category:"Wedding",plan:"starter"});
const[status,setStatus]=useState("Layer 5 ready."),[systemCheck,setSystemCheck]=useState(null),[userLoc,setUserLoc]=useState(null),[aiPlan,setAiPlan]=useState(null);
const activeCategory=categories.find(i=>i.key===activeKey)||categories[0];
const filteredVendors=useMemo(()=>vendors.filter(v=>{const mc=activeCategory.label==="All"||v.category===activeCategory.label;const mq=`${v.name} ${v.service} ${v.city} ${v.category}`.toLowerCase().includes(query.toLowerCase());return mc&&mq}),[query,activeCategory,vendors]);
const vendorMRR=vendors.reduce((s,v)=>s+Number(v.revenue||0),0),bookingFees=bookings.reduce((s,b)=>s+Number(b.commission||0),0),totalRevenue=vendorMRR+bookingFees;
const nav=[["live",ShieldCheck,"Live Setup"],["marketplace",Store,"Marketplace"],["map",Map,"Map + GPS"],["builder",Wand2,"Event Builder"],["ai",Brain,"AI Premium"],["vendors",UserPlus,"Vendor Join"],["outreach",Mail,"Outreach"],["mobile",Smartphone,"Mobile"],["plans",Crown,"Plans"],["bookings",ClipboardList,"Bookings"],["dashboard",LayoutDashboard,"Dashboard"]];
function chooseCategory(k){setActiveKey(k);setTab("builder")}
async function runSystemCheck(){const d=await getJson("/api/system-check");setSystemCheck(d);setStatus(d.message||"System check complete.")}
async function addVendor(){if(!vendorForm.name.trim()){setStatus("Add a vendor name first.");return}const p=plans.find(i=>i.key===vendorForm.plan)||plans[0];const nv={name:vendorForm.name,service:vendorForm.service||"Event Vendor",city:vendorForm.city||"Local Area",category:vendorForm.category,price:vendorForm.price||"Contact for pricing",rating:"New",badge:p.name,plan:p.key,revenue:p.amount};setVendors(prev=>[nv,...prev]);setVendorForm({name:"",service:"",city:"",price:"",category:"Wedding",plan:"starter"});const d=await postJson("/api/vendors/create",{vendor:nv});setStatus(d.message||"Vendor added.")}
function requestBooking(v){const b={id:`BK-${Math.floor(1000+Math.random()*9000)}`,customer:"New Customer",vendor:v.name,amount:1000,commission:100,status:"Requested"};setBookings(prev=>[b,...prev]);postJson("/api/bookings/create",{booking:b}).then(d=>setStatus(d.message||`Booking request created for ${v.name}.`));setTab("bookings")}
async function activatePlan(k){const d=await postJson("/api/vendor-subscriptions/create",{plan:k,businessName});setStatus(d.message||"Plan activation route called.");if(d.url)window.location.href=d.url}
function detectLocation(){navigator.geolocation?.getCurrentPosition(p=>{setUserLoc({lat:p.coords.latitude,lng:p.coords.longitude});setStatus("GPS location detected.")},()=>setStatus("GPS unavailable."))}
async function runAi(){const d=await postJson("/api/ai/premium-plan",{eventName,eventLocation,eventBudget,category:activeCategory.label});setAiPlan(d.plan);setStatus(d.message||"AI plan generated.")}

return <main className="min-h-screen p-6"><div className="mx-auto max-w-7xl">
<header className="card mb-6 flex flex-wrap justify-between gap-6 items-center"><div className="flex gap-5 items-center"><div className="orb"/><div><p className="text-sm uppercase tracking-[.25em] text-stone-500">Layer 5 Scale Pack</p><h1 className="text-4xl md:text-5xl font-light tracking-wide">GatherGenius</h1><p className="text-stone-500 mt-2">Map, GPS, AI premium, mobile, outreach, payments and database by {businessName}</p></div></div><button onClick={runSystemCheck} className="btn primary"><TestTube2 className="inline h-4 w-4 mr-2"/>Run System Check</button></header>
<nav className="card mb-6 flex gap-2 flex-wrap">{nav.map(([k,Icon,label])=><button key={k} onClick={()=>setTab(k)} className={`btn ${tab===k?"primary":""}`}><Icon className="inline h-4 w-4 mr-2"/>{label}</button>)}</nav>

{tab==="live"&&<section><h2 className="text-3xl font-light mb-4 flex items-center gap-2"><ShieldCheck/> Execute 1–4</h2><div className="grid lg:grid-cols-2 gap-4 mb-4"><div className="card"><h3 className="text-2xl font-light mb-3">1. Supabase + Stripe</h3><button onClick={runSystemCheck} className="btn primary">Run Env Check</button>{systemCheck&&<div className="mt-4 space-y-2 text-sm">{Object.entries(systemCheck.checks||{}).map(([k,v])=><p key={k} className={v?"good":"warn"}>{v?"✓":"•"} {k}: {String(v)}</p>)}</div>}</div><div className="card"><h3 className="text-2xl font-light mb-3">2. Database Tests</h3><button onClick={()=>postJson("/api/test/seed-vendor").then(d=>setStatus(d.message))} className="btn mr-2">Test Vendor Save</button><button onClick={()=>postJson("/api/test/seed-booking").then(d=>setStatus(d.message))} className="btn">Test Booking Save</button></div><div className="card"><h3 className="text-2xl font-light mb-3">3. Stripe Tests</h3><button onClick={()=>activatePlan("featured")} className="btn primary mr-2">Featured Checkout</button><button onClick={()=>activatePlan("elite")} className="btn primary">Elite Checkout</button></div><div className="card"><h3 className="text-2xl font-light mb-3">4. Revenue Execution</h3><p className="text-stone-500">Add 5 real vendors and pitch Featured placement at $49/month.</p></div></div><div className="card"><p>Status: {status}</p></div></section>}

{tab==="marketplace"&&<><section className="card mb-6"><h2 className="text-4xl md:text-6xl font-light leading-tight">Find vendors and create booking requests.</h2><p className="text-stone-500 mt-4">Now includes map/GPS, AI premium planner, mobile starter and outreach automation docs.</p></section><SearchBox query={query} setQuery={setQuery}/><CategoryButtons categories={categories} activeKey={activeKey} chooseCategory={chooseCategory}/><VendorGrid vendors={filteredVendors} requestBooking={requestBooking}/></>}

{tab==="map"&&<section><h2 className="text-3xl font-light mb-4 flex items-center gap-2"><MapPin/> Real Map + GPS</h2><div className="grid lg:grid-cols-3 gap-4"><div className="card lg:col-span-2 min-h-[420px] flex items-center justify-center text-center"><div><MapPin className="mx-auto mb-3" size={44}/><h3 className="text-2xl font-light">Map Ready</h3><p className="text-stone-500 mt-2">Add Google Maps keys for live Places. GPS detection works now.</p><button onClick={detectLocation} className="btn primary mt-4"><Navigation className="inline h-4 w-4 mr-2"/>Detect My GPS</button>{userLoc&&<p className="mt-4 text-sm">Lat: {userLoc.lat.toFixed(4)} / Lng: {userLoc.lng.toFixed(4)}</p>}</div></div><div className="space-y-3">{vendors.map(v=><div key={v.name} className="card"><h3>{v.name}</h3><p className="text-sm text-stone-500">{v.city}</p><p className="text-sm">Lat {v.lat} / Lng {v.lng}</p></div>)}</div></div></section>}

{tab==="builder"&&<section><div className="grid lg:grid-cols-3 gap-6"><div className="card"><h2 className="text-3xl font-light mb-4">Event Builder</h2><Field label="Event Name" value={eventName} set={setEventName}/><Field label="Location" value={eventLocation} set={setEventLocation}/><Field label="Budget" value={eventBudget} set={setEventBudget} type="number"/><label className="block mt-4"><span className="text-sm text-stone-500">Category</span><select value={activeKey} onChange={e=>setActiveKey(e.target.value)} className="mt-1 w-full rounded-2xl border border-stone-200 px-4 py-3 outline-none bg-white">{categories.filter(i=>i.key!=="all").map(i=><option key={i.key} value={i.key}>{i.label}</option>)}</select></label></div><div className="lg:col-span-2 space-y-5"><div className="grid md:grid-cols-3 gap-4"><Metric icon={Wallet} label="Budget" value={money(eventBudget)}/><Metric icon={Users} label="Suggested Vendors" value={filteredVendors.length}/><Metric icon={ClipboardList} label="Checklist Items" value={activeCategory.checklist.length}/></div><div className="card"><h2 className="text-3xl font-light mb-2">{eventName}</h2><p className="text-stone-500 mb-6">{activeCategory.label} event in {eventLocation}</p><div className="grid md:grid-cols-2 gap-5"><List title="Suggested Zones" items={activeCategory.zones}/><List title="AI Checklist" items={activeCategory.checklist} checklist/></div></div></div></div></section>}

{tab==="ai"&&<section><h2 className="text-3xl font-light mb-4 flex items-center gap-2"><Brain/> AI Event Planner Premium</h2><div className="grid md:grid-cols-2 gap-4"><div className="card"><p className="text-stone-500 mb-4">Premium planner generates timeline, budget notes, vendor needs and next steps. Uses OpenAI when key is added, safe fallback otherwise.</p><button onClick={runAi} className="btn primary">Generate Premium Plan</button><button onClick={()=>activatePlan("ai")} className="btn ml-2">Subscribe $19/mo</button></div><div className="card"><h3 className="text-xl font-light mb-3">AI Output</h3>{aiPlan?<div className="space-y-2">{aiPlan.map((i,idx)=><p key={idx}><CheckCircle2 className="inline h-4 w-4 mr-2 text-emerald-700"/>{i}</p>)}</div>:<p className="text-stone-500">No premium plan generated yet.</p>}</div></div></section>}

{tab==="vendors"&&<section><h2 className="text-3xl font-light mb-4 flex items-center gap-2"><UserPlus/> Vendor Join</h2><div className="grid lg:grid-cols-2 gap-6"><div className="card"><Field label="Business Name" value={vendorForm.name} set={v=>setVendorForm({...vendorForm,name:v})}/><Field label="Service" value={vendorForm.service} set={v=>setVendorForm({...vendorForm,service:v})}/><Field label="City" value={vendorForm.city} set={v=>setVendorForm({...vendorForm,city:v})}/><Field label="Price Range" value={vendorForm.price} set={v=>setVendorForm({...vendorForm,price:v})}/><button onClick={addVendor} className="btn primary mt-5 w-full">Add Vendor</button></div><div className="card"><h3 className="text-2xl font-light mb-4">Live Database Ready</h3><p><Database className="inline h-4 w-4 mr-2"/>/api/vendors/create</p><p><ClipboardList className="inline h-4 w-4 mr-2"/>/api/bookings/create</p><p><CreditCard className="inline h-4 w-4 mr-2"/>/api/vendor-subscriptions/create</p></div></div></section>}

{tab==="outreach"&&<section><h2 className="text-3xl font-light mb-4 flex items-center gap-2"><Mail/> Automated Vendor Outreach</h2><div className="grid md:grid-cols-3 gap-4"><div className="card"><h3 className="text-xl">DM Script</h3><p className="text-stone-500 mt-2">Hey — I launched GatherGenius to send vendors real booking requests. Want a free listing?</p></div><div className="card"><h3 className="text-xl">Daily Workflow</h3><p className="text-stone-500 mt-2">Contact 20 vendors/day, add 5, pitch Featured at $49/month.</p></div><div className="card"><h3 className="text-xl">CSV Included</h3><p className="text-stone-500 mt-2">Use the outreach folder in this ZIP for lead tracking.</p></div></div></section>}

{tab==="mobile"&&<section><h2 className="text-3xl font-light mb-4 flex items-center gap-2"><Smartphone/> Mobile App Version</h2><div className="card"><p className="text-stone-500">Expo mobile starter is included in folder 02. It connects to the same web backend routes.</p></div></section>}

{tab==="plans"&&<section><h2 className="text-3xl font-light mb-4 flex items-center gap-2"><Crown/> Pricing Tiers</h2><div className="grid md:grid-cols-4 gap-4">{plans.map(p=><div className="card" key={p.key}><h3 className="text-2xl font-light">{p.name}</h3><p className="text-4xl font-light my-4">{p.price}</p>{p.features.map(f=><p key={f}><CheckCircle2 className="inline h-4 w-4 mr-2 text-emerald-700"/>{f}</p>)}<button onClick={()=>activatePlan(p.key)} className="btn primary mt-5 w-full">Activate</button></div>)}</div></section>}

{tab==="bookings"&&<section><h2 className="text-3xl font-light mb-4 flex items-center gap-2"><ClipboardList/> Booking Pipeline</h2><div className="grid gap-3">{bookings.map(b=><div key={b.id} className="card grid md:grid-cols-6 gap-3 items-center"><p>{b.id}</p><p>{b.customer}</p><p>{b.vendor}</p><p>{money(b.amount)}</p><p className="text-emerald-700">{money(b.commission)}</p><p>{b.status}</p></div>)}</div></section>}

{tab==="dashboard"&&<section><h2 className="text-3xl font-light mb-4 flex items-center gap-2"><LayoutDashboard/> Dashboard</h2><div className="grid md:grid-cols-4 gap-4 mb-6"><Metric icon={DollarSign} label="Platform Revenue" value={money(totalRevenue)}/><Metric icon={Crown} label="Vendor MRR" value={money(vendorMRR)}/><Metric icon={CreditCard} label="Booking Fees" value={money(bookingFees)}/><Metric icon={Building2} label="Vendors" value={vendors.length}/></div></section>}

<footer className="mt-10 text-sm text-stone-500">© 2026 GatherGenius. Revenue directed to {businessName}. {status}</footer>
</div></main>}
function SearchBox({query,setQuery}){return <section className="card mb-6"><div className="flex gap-3"><div className="flex-1 rounded-full bg-white border border-stone-200 px-5 py-4 flex gap-3 items-center"><Search className="text-stone-400"/><input value={query} onChange={e=>setQuery(e.target.value)} placeholder="Search vendors, venues, cities, services..." className="w-full bg-transparent outline-none"/></div><button className="btn primary">Search</button></div></section>}
function CategoryButtons({categories,activeKey,chooseCategory}){return <div className="flex flex-wrap gap-2 mb-6">{categories.map(c=><button key={c.key} onClick={()=>chooseCategory(c.key)} className={`btn ${activeKey===c.key?"primary":""}`}>{c.label}</button>)}</div>}
function Field({label,value,set,type="text"}){return <label className="block mb-4"><span className="text-sm text-stone-500">{label}</span><input type={type} value={value} onChange={e=>set(e.target.value)} className="mt-1 w-full rounded-2xl border border-stone-200 px-4 py-3 outline-none"/></label>}
function List({title,items,checklist=false}){return <div><h3 className="text-xl font-light mb-3">{title}</h3>{items.map(i=><div key={i} className="rounded-2xl border border-stone-200 bg-white px-4 py-3 mb-2">{checklist&&<CheckCircle2 className="inline h-4 w-4 mr-2 text-emerald-700"/>}{i}</div>)}</div>}
function VendorGrid({vendors,requestBooking}){return <div className="grid md:grid-cols-2 xl:grid-cols-3 gap-4">{vendors.map(v=><div className="card" key={v.name}><div className="flex justify-between gap-4"><div><h3 className="text-2xl font-light">{v.name}</h3><p className="text-stone-500">{v.service}</p></div><span className="flex items-center gap-1 text-sm"><Star className="h-4 w-4"/> {v.rating}</span></div><p className="mt-4 text-sm text-stone-500 flex gap-1 items-center"><MapPin className="h-4 w-4"/> {v.city}</p><p className="mt-3">{v.price}</p><div className="flex flex-wrap gap-2 mt-4"><span className="rounded-full bg-white border border-stone-200 px-3 py-1 text-sm">{v.category}</span><span className="rounded-full bg-white border border-stone-200 px-3 py-1 text-sm">{v.badge}</span></div><button onClick={()=>requestBooking(v)} className="btn primary mt-5 w-full"><Send className="inline h-4 w-4 mr-2"/>Request Booking</button></div>)}</div>}
function Metric({icon:Icon,label,value}){return <div className="card"><Icon className="mb-3"/><p className="text-sm text-stone-500">{label}</p><p className="text-2xl">{value}</p></div>}
